import React, { useState } from 'react';
import './UserManagement.css';

const UserManagement = () => {
  const [users] = useState([
    { id: 1, username: 'darlingohioo', email: 'ruhiddinov03@mail.com', level: 5, points: 9800, role: 'admin', status: 'active', joinDate: '2023-02-12' },
    { id: 2, username: 'DarkLord', email: 'darklord@mail.com', level: 5, points: 12500, role: 'user', status: 'active', joinDate: '2023-01-15' },
    { id: 3, username: 'MangaMaster', email: 'master@mail.com', level: 5, points: 9800, role: 'moderator', status: 'active', joinDate: '2023-02-20' },
    { id: 4, username: 'WeebQueen', email: 'queen@mail.com', level: 4, points: 7200, role: 'user', status: 'active', joinDate: '2023-03-10' },
    { id: 5, username: 'AnimeLover', email: 'lover@mail.com', level: 4, points: 6500, role: 'user', status: 'suspended', joinDate: '2023-03-25' },
    { id: 6, username: 'KawaiiChan', email: 'kawaii@mail.com', level: 3, points: 4200, role: 'user', status: 'active', joinDate: '2023-04-05' },
    { id: 7, username: 'OtakuKing', email: 'king@mail.com', level: 3, points: 3800, role: 'user', status: 'active', joinDate: '2023-04-15' },
    { id: 8, username: 'Senpai', email: 'senpai@mail.com', level: 2, points: 1500, role: 'user', status: 'active', joinDate: '2023-05-01' }
  ]);

  const [searchTerm, setSearchTerm] = useState('');
  const [selectedUsers, setSelectedUsers] = useState([]);

  const handleSelectUser = (userId) => {
    setSelectedUsers(prev => 
      prev.includes(userId) 
        ? prev.filter(id => id !== userId)
        : [...prev, userId]
    );
  };

  const handleSelectAll = () => {
    if (selectedUsers.length === users.length) {
      setSelectedUsers([]);
    } else {
      setSelectedUsers(users.map(user => user.id));
    }
  };

  const handleRoleChange = (userId, newRole) => {
    console.log(`Changing role for user ${userId} to ${newRole}`);
  };

  const handleStatusChange = (userId, newStatus) => {
    console.log(`Changing status for user ${userId} to ${newStatus}`);
  };

  const filteredUsers = users.filter(user =>
    user.username.toLowerCase().includes(searchTerm.toLowerCase()) ||
    user.email.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="user-management">
      <h2>Управление пользователями</h2>
      
      <div className="management-header">
        <div className="search-box">
          <i className="fas fa-search"></i>
          <input
            type="text"
            placeholder="Поиск пользователей..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        
        <div className="action-buttons">
          <button className="action-btn">
            <i className="fas fa-plus"></i>
            Добавить пользователя
          </button>
          <button className="action-btn">
            <i className="fas fa-file-export"></i>
            Экспорт
          </button>
        </div>
      </div>
      
      <div className="users-table-container">
        <table className="users-table">
          <thead>
            <tr>
              <th>
                <input
                  type="checkbox"
                  checked={selectedUsers.length === users.length && users.length > 0}
                  onChange={handleSelectAll}
                />
              </th>
              <th>Пользователь</th>
              <th>Уровень</th>
              <th>Роль</th>
              <th>Статус</th>
              <th>Дата регистрации</th>
              <th>Действия</th>
            </tr>
          </thead>
          <tbody>
            {filteredUsers.map(user => (
              <tr key={user.id}>
                <td>
                  <input
                    type="checkbox"
                    checked={selectedUsers.includes(user.id)}
                    onChange={() => handleSelectUser(user.id)}
                  />
                </td>
                <td>
                  <div className="user-cell">
                    <div className="user-avatar">
                      <i className="fas fa-user"></i>
                    </div>
                    <div className="user-info">
                      <div className="username">{user.username}</div>
                      <div className="user-email">{user.email}</div>
                    </div>
                  </div>
                </td>
                <td>
                  <div className="level-cell">
                    <span className="level-badge">Уровень {user.level}</span>
                    <span className="points">{user.points} очков</span>
                  </div>
                </td>
                <td>
                  <select
                    value={user.role}
                    onChange={(e) => handleRoleChange(user.id, e.target.value)}
                    className="role-select"
                  >
                    <option value="user">Пользователь</option>
                    <option value="moderator">Модератор</option>
                    <option value="admin">Администратор</option>
                  </select>
                </td>
                <td>
                  <select
                    value={user.status}
                    onChange={(e) => handleStatusChange(user.id, e.target.value)}
                    className={`status-select ${user.status}`}
                  >
                    <option value="active" className="active">Активен</option>
                    <option value="suspended" className="suspended">Заблокирован</option>
                    <option value="inactive" className="inactive">Неактивен</option>
                  </select>
                </td>
                <td>{user.joinDate}</td>
                <td>
                  <div className="action-buttons-cell">
                    <button className="icon-btn edit" title="Редактировать">
                      <i className="fas fa-edit"></i>
                    </button>
                    <button className="icon-btn delete" title="Удалить">
                      <i className="fas fa-trash"></i>
                    </button>
                    <button className="icon-btn message" title="Написать">
                      <i className="fas fa-envelope"></i>
                    </button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
      
      {selectedUsers.length > 0 && (
        <div className="bulk-actions">
          <span>Выбрано: {selectedUsers.length} пользователей</span>
          <div className="bulk-buttons">
            <button className="bulk-btn">
              <i className="fas fa-user-check"></i>
              Изменить роль
            </button>
            <button className="bulk-btn">
              <i className="fas fa-ban"></i>
              Заблокировать
            </button>
            <button className="bulk-btn delete">
              <i className="fas fa-trash"></i>
              Удалить
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default UserManagement;
